import { Component, inject, signal } from '@angular/core';
import { AXFileService, AXFileSizeFormatter } from '@acorex/core/file';

@Component({
  selector: 'app-file-usage',
  template: `
    <button type="button" (click)="pickAndProcess()">Pick image</button>
    @if (preview()) {
      <p>{{ preview()!.name }} — {{ preview()!.sizeLabel }}</p>
    }
  `,
})
export class FileUsageComponent {
  private fileService = inject(AXFileService);
  private sizeFormatter = new AXFileSizeFormatter();

  preview = signal<{ name: string; sizeLabel: string } | null>(null);

  async pickAndProcess() {
    const files = await this.fileService.choose({
      accept: 'image/*',
      multiple: false,
    });
    if (!files.length) return;

    const file = files[0];

    // Native File/Blob — use .size directly
    const sizeLabel = this.sizeFormatter.format(file.size);

    // Convert to data-URL base64 for upload or preview
    const dataUrl = await this.fileService.blobToBase64(file);

    // Base64 size helpers — only for data-URL strings
    if (this.fileService.isBase64(dataUrl)) {
      const bytes = this.fileService.getBase64Size(dataUrl);
      console.log(this.fileService.getSize(dataUrl)); // same byte count
    }

    this.preview.set({ name: file.name, sizeLabel });
  }
}

import { Component, inject, signal } from '@angular/core';
import { AXFileService } from '@acorex/core/file';

@Component({
  selector: 'app-upload-button',
  template: `
    <button type="button" (click)="selectDocuments()">Upload PDFs</button>
    <button type="button" (click)="selectImages()">Upload images</button>
    @for (file of selected(); track file.name) {
      <p>{{ file.name }} — {{ file.size }} bytes</p>
    }
  `,
})
export class UploadButtonComponent {
  private fileService = inject(AXFileService);
  protected selected = signal<File[]>([]);

  async selectDocuments() {
    const files = await this.fileService.choose({ accept: '.pdf,.doc,.docx', multiple: true });
    this.selected.set(files);
  }

  async selectImages() {
    const files = await this.fileService.choose({ accept: 'image/*', multiple: true });
    this.selected.set(files);
  }
}

import { Component, inject } from '@angular/core';
import { AXFileService } from '@acorex/core/file';

@Component({
  selector: 'app-voice-recorder',
  template: `<button type="button" (click)="saveRecording()">Save</button>`,
})
export class VoiceRecorderComponent {
  private fileService = inject(AXFileService);
  private recordedBlob: Blob | null = null;

  // Called when your recorder emits a Blob
  onRecordingComplete(blob: Blob) {
    this.recordedBlob = blob;
  }

  async saveRecording() {
    if (!this.recordedBlob) return;

    try {
      const dataUrl = await this.fileService.blobToBase64(this.recordedBlob);
      // dataUrl looks like: data:audio/webm;base64,GkXf...
      await this.sendToServer(dataUrl);
    } catch (err) {
      console.error('Conversion failed', err);
    }
  }

  private sendToServer(payload: string) {
    /* POST payload to API */
  }
}

import { Component, inject } from '@angular/core';
import { AXFileService } from '@acorex/core/file';

@Component({
  selector: 'app-file-message',
  template: `
    <p>{{ fileName() }}</p>
    <p>{{ displaySize() | format: 'filesize' | async }}</p>
  `,
})
export class FileMessageComponent {
  private fileService = inject(AXFileService);

  // message.content may be a data-URL string OR a File object
  message = { content: 'data:application/pdf;base64,JVBERi0x...', name: 'report.pdf' };

  fileName = () => this.message.name;

  displaySize = () => {
    const content = this.message.content;
    if (typeof content === 'string' && this.fileService.isBase64(content)) {
      return this.fileService.getBase64Size(content);
    }
    // For native File objects, use .size directly
    return (content as File).size ?? 0;
  };
}

