import { Component, inject } from '@angular/core';
import { AXUploaderService } from '@acorex/cdk/uploader';

@Component({
  selector: 'app-custom-uploader',
  template: `<button type="button" (click)="browse()">Add files</button>`,
})
export class CustomUploaderComponent {
  private uploader = inject(AXUploaderService);

  async browse() {
    const requests = await this.uploader.browse({
      multiple: true,
      accept: 'image/*,.pdf',
    });
    // Each AXUploadRequest wraps a File and tracks upload progress
    console.log(requests.map((r) => r.file.name));
  }
}
